import os
import re
from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras

app = Flask(__name__)

# Database configuration from environment variables
DB_CONFIG = {
    'host': os.environ.get('DB_HOST', 'localhost'),
    'port': os.environ.get('DB_PORT', '5432'),
    'dbname': os.environ.get('DB_NAME', 'analytics'),
    'user': os.environ.get('DB_USER', 'postgres'),
    'password': os.environ.get('DB_PASSWORD', 'postgres'),
}

# Whitelist of allowed tables and columns for security
ALLOWED_TABLES = os.environ.get('ALLOWED_TABLES', '').split(',') if os.environ.get('ALLOWED_TABLES') else []
ALLOWED_OPERATORS = {'=', '!=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL', 'BETWEEN'}
ALLOWED_AGGREGATIONS = {'COUNT', 'SUM', 'AVG', 'MIN', 'MAX'}
ALLOWED_ORDER_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 10000
DEFAULT_LIMIT = 100


def get_db_connection():
    """Create and return a database connection."""
    conn = psycopg2.connect(**DB_CONFIG)
    return conn


def validate_identifier(identifier):
    """Validate that an identifier (table/column name) is safe."""
    if not identifier:
        return False
    # Only allow alphanumeric characters, underscores, and dots (for schema.table)
    pattern = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_.]*$')
    return bool(pattern.match(identifier))


def validate_table_name(table_name):
    """Validate table name against whitelist if configured, and check format."""
    if not validate_identifier(table_name):
        return False, "Invalid table name format"
    if ALLOWED_TABLES and table_name not in ALLOWED_TABLES:
        return False, f"Table '{table_name}' is not in the allowed tables list"
    return True, None


def get_table_columns(conn, table_name):
    """Fetch actual column names from the database for validation."""
    schema = 'public'
    table = table_name
    if '.' in table_name:
        parts = table_name.split('.', 1)
        schema = parts[0]
        table = parts[1]

    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT column_name 
            FROM information_schema.columns 
            WHERE table_schema = %s AND table_name = %s
            """,
            (schema, table)
        )
        return {row[0] for row in cur.fetchall()}


def validate_columns(requested_columns, available_columns):
    """Validate requested columns against available columns."""
    invalid = []
    for col in requested_columns:
        # Strip aggregation functions if present
        clean_col = col
        for agg in ALLOWED_AGGREGATIONS:
            if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                clean_col = col[len(agg)+1:-1]
                break
        if clean_col != '*' and clean_col not in available_columns:
            invalid.append(col)
    return invalid


def build_select_clause(columns, available_columns):
    """Build the SELECT clause with proper quoting."""
    if not columns:
        return "*", []

    select_parts = []
    for col in columns:
        # Check for aggregation functions
        agg_match = None
        for agg in ALLOWED_AGGREGATIONS:
            if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                inner_col = col[len(agg)+1:-1].strip()
                agg_match = agg
                break

        if agg_match:
            if inner_col == '*':
                select_parts.append(f"{agg_match}(*)")
            elif inner_col in available_columns:
                select_parts.append(f"{agg_match}({psycopg2.extensions.quote_ident(inner_col, None)})")
            else:
                raise ValueError(f"Invalid column in aggregation: {inner_col}")
        else:
            if col == '*':
                select_parts.append('*')
            elif col in available_columns:
                select_parts.append(psycopg2.extensions.quote_ident(col, None))
            else:
                raise ValueError(f"Invalid column: {col}")

    return ", ".join(select_parts), []


def quote_ident_with_conn(identifier, conn):
    """Quote an identifier using psycopg2."""
    return psycopg2.extensions.quote_ident(identifier, conn)


def build_where_clause(filters, available_columns, conn):
    """
    Build WHERE clause from filter conditions.
    
    Filters format:
    [
        {"column": "name", "operator": "=", "value": "John"},
        {"column": "age", "operator": ">", "value": 25},
        {"column": "status", "operator": "IN", "value": ["active", "pending"]},
        {"column": "deleted_at", "operator": "IS NULL"},
        {"column": "score", "operator": "BETWEEN", "value": [10, 100]},
        {"logic": "OR", "column": "city", "operator": "=", "value": "NYC"}
    ]
    """
    if not filters:
        return "", []

    conditions = []
    params = []
    logic_operators = []

    for f in filters:
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')
        logic = f.get('logic', 'AND').upper()

        if logic not in ('AND', 'OR'):
            raise ValueError(f"Invalid logic operator: {logic}")

        if not column or column not in available_columns:
            raise ValueError(f"Invalid or disallowed column in filter: {column}")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")

        quoted_col = quote_ident_with_conn(column, conn)

        if operator in ('IS NULL', 'IS NOT NULL'):
            conditions.append(f"{quoted_col} {operator}")
        elif operator == 'BETWEEN':
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list of two values")
            conditions.append(f"{quoted_col} BETWEEN %s AND %s")
            params.extend(value)
        elif operator in ('IN', 'NOT IN'):
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise ValueError(f"{operator} operator requires a non-empty list of values")
            placeholders = ', '.join(['%s'] * len(value))
            conditions.append(f"{quoted_col} {operator} ({placeholders})")
            params.extend(value)
        else:
            conditions.append(f"{quoted_col} {operator} %s")
            params.append(value)

        if len(conditions) > 1:
            logic_operators.append(logic)
        else:
            logic_operators.append(None)

    # Build the full WHERE clause
    where_str = conditions[0]
    for i in range(1, len(conditions)):
        logic = logic_operators[i] if logic_operators[i] else 'AND'
        where_str += f" {logic} {conditions[i]}"

    return f"WHERE {where_str}", params


def build_group_by_clause(group_by, available_columns, conn):
    """Build GROUP BY clause."""
    if not group_by:
        return ""

    parts = []
    for col in group_by:
        if col not in available_columns:
            raise ValueError(f"Invalid column in GROUP BY: {col}")
        parts.append(quote_ident_with_conn(col, conn))

    return f"GROUP BY {', '.join(parts)}"


def build_having_clause(having_filters, conn):
    """
    Build HAVING clause for aggregate filters.
    
    Format:
    [
        {"aggregation": "COUNT", "column": "*", "operator": ">", "value": 5},
        {"aggregation": "AVG", "column": "price", "operator": ">=", "value": 100}
    ]
    """
    if not having_filters:
        return "", []

    conditions = []
    params = []

    for f in having_filters:
        agg = f.get('aggregation', '').upper()
        column = f.get('column', '*')
        operator = f.get('operator', '=').upper()
        value = f.get('value')

        if agg not in ALLOWED_AGGREGATIONS:
            raise ValueError(f"Invalid aggregation in HAVING: {agg}")
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator in HAVING: {operator}")

        if column == '*':
            agg_expr = f"{agg}(*)"
        elif validate_identifier(column):
            agg_expr = f"{agg}({quote_ident_with_conn(column, conn)})"
        else:
            raise ValueError(f"Invalid column in HAVING: {column}")

        conditions.append(f"{agg_expr} {operator} %s")
        params.append(value)

    logic = " AND ".join(conditions)
    return f"HAVING {logic}", params


def build_order_by_clause(order_by, available_columns, conn):
    """
    Build ORDER BY clause.
    
    Format:
    [
        {"column": "name", "direction": "ASC"},
        {"column": "created_at", "direction": "DESC"}
    ]
    """
    if not order_by:
        return ""

    parts = []
    for o in order_by:
        column = o.get('column')
        direction = o.get('direction', 'ASC').upper()

        if column not in available_columns:
            # Check if it's an aggregation expression
            is_agg = False
            for agg in ALLOWED_AGGREGATIONS:
                if column and column.upper().startswith(f"{agg}("):
                    is_agg = True
                    break
            if not is_agg:
                raise ValueError(f"Invalid column in ORDER BY: {column}")
            # For aggregation columns in ORDER BY, we need to reconstruct
            parts.append(f"{column} {direction}")
            continue

        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: {direction}")

        parts.append(f"{quote_ident_with_conn(column, conn)} {direction}")

    return f"ORDER BY {', '.join(parts)}"


def build_query(table, columns, filters, group_by, having, order_by, limit, offset, conn, available_columns):
    """Build the complete SQL query."""
    params = []

    # SELECT
    select_clause, select_params = build_select_clause(columns, available_columns)
    params.extend(select_params)

    # Quote table name properly
    if '.' in table:
        schema, tbl = table.split('.', 1)
        quoted_table = f"{quote_ident_with_conn(schema, conn)}.{quote_ident_with_conn(tbl, conn)}"
    else:
        quoted_table = quote_ident_with_conn(table, conn)

    query = f"SELECT {select_clause} FROM {quoted_table}"

    # WHERE
    where_clause, where_params = build_where_clause(filters, available_columns, conn)
    if where_clause:
        query += f" {where_clause}"
        params.extend(where_params)

    # GROUP BY
    group_clause = build_group_by_clause(group_by, available_columns, conn)
    if group_clause:
        query += f" {group_clause}"

    # HAVING
    having_clause, having_params = build_having_clause(having, conn)
    if having_clause:
        query += f" {having_clause}"
        params.extend(having_params)

    # ORDER BY
    order_clause = build_order_by_clause(order_by, available_columns, conn)
    if order_clause:
        query += f" {order_clause}"

    # LIMIT & OFFSET
    if limit is not None:
        limit = min(int(limit), MAX_LIMIT)
    else:
        limit = DEFAULT_LIMIT
    query += f" LIMIT %s"
    params.append(limit)

    if offset is not None:
        query += f" OFFSET %s"
        params.append(int(offset))

    return query, params


@app.route('/api/query', methods=['POST'])
def dynamic_query():
    """
    Execute a dynamic query based on the request body.
    
    Request body:
    {
        "table": "users",
        "columns": ["id", "name", "email"],
        "filters": [
            {"column": "status", "operator": "=", "value": "active"},
            {"column": "age", "operator": ">", "value": 18}
        ],
        "group_by": ["status"],
        "having": [
            {"aggregation": "COUNT", "column": "*", "operator": ">", "value": 5}
        ],
        "order_by": [
            {"column": "name", "direction": "ASC"}
        ],
        "limit": 50,
        "offset": 0
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body is required"}), 400

        table = data.get('table')
        if not table:
            return jsonify({"error": "Table name is required"}), 400

        # Validate table name
        is_valid, error_msg = validate_table_name(table)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

        columns = data.get('columns', [])
        filters = data.get('filters', [])
        group_by = data.get('group_by', [])
        having = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit', DEFAULT_LIMIT)
        offset = data.get('offset', 0)

        conn = get_db_connection()
        try:
            # Get available columns for validation
            available_columns = get_table_columns(conn, table)
            if not available_columns:
                return jsonify({"error": f"Table '{table}' not found or has no columns"}), 404

            # Validate requested columns
            if columns:
                # Extract raw column names (strip aggregation functions)
                raw_columns = []
                for col in columns:
                    clean_col = col
                    for agg in ALLOWED_AGGREGATIONS:
                        if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                            clean_col = col[len(agg)+1:-1].strip()
                            break
                    if clean_col != '*':
                        raw_columns.append(clean_col)

                invalid_cols = [c for c in raw_columns if c not in available_columns]
                if invalid_cols:
                    return jsonify({
                        "error": f"Invalid columns: {', '.join(invalid_cols)}",
                        "available_columns": sorted(list(available_columns))
                    }), 400

            # Build and execute query
            query, params = build_query(
                table, columns, filters, group_by, having, order_by,
                limit, offset, conn, available_columns
            )

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, params)
                rows = cur.fetchall()

                # Get column names from cursor description
                col_names = [desc[0] for desc in cur.description] if cur.description else []

            # Convert to list of dicts
            results = [dict(row) for row in rows]

            return jsonify({
                "table": table,
                "columns": col_names,
                "row_count": len(results),
                "data": results,
                "query_info": {
                    "limit": limit,
                    "offset": offset
                }
            })

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500
    except Exception as e:
        return jsonify({"error": f"Internal error: {str(e)}"}), 500


@app.route('/api/tables', methods=['GET'])
def list_tables():
    """List all available tables."""
    try:
        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT table_schema, table_name 
                    FROM information_schema.tables 
                    WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
                    AND table_type = 'BASE TABLE'
                    ORDER BY table_schema, table_name
                    """
                )
                tables = []
                for row in cur.fetchall():
                    full_name = f"{row[0]}.{row[1]}" if row[0] != 'public' else row[1]
                    if ALLOWED_TABLES and full_name not in ALLOWED_TABLES and row[1] not in ALLOWED_TABLES:
                        continue
                    tables.append({
                        "schema": row[0],
                        "table": row[1],
                        "full_name": full_name
                    })

            return jsonify({"tables": tables})
        finally:
            conn.close()

    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/tables/<table_name>/columns', methods=['GET'])
def list_columns(table_name):
    """List all columns for a given table."""
    try:
        is_valid, error_msg = validate_table_name(table_name)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

        schema = 'public'
        table = table_name
        if '.' in table_name:
            parts = table_name.split('.', 1)
            schema = parts[0]
            table = parts[1]

        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT column_name, data_type, is_nullable, column_default
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    ORDER BY ordinal_position
                    """,
                    (schema, table)
                )
                columns = []
                for row in cur.fetchall():
                    columns.append({
                        "name": row[0],
                        "type": row[1],
                        "nullable": row[2] == 'YES',
                        "default": row[3]
                    })

            if not columns:
                return jsonify({"error": f"Table '{table_name}' not found"}), 404

            return jsonify({
                "table": table_name,
                "columns": columns
            })
        finally:
            conn.close()

    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/query/count', methods=['POST'])
def count_query():
    """Get the count of rows matching the filter conditions."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body is required"}), 400

        table = data.get('table')
        if not table:
            return jsonify({"error": "Table name is required"}), 400

        is_valid, error_msg = validate_table_name(table)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

        filters = data.get('filters', [])

        conn = get_db_connection()
        try:
            available_columns = get_table_columns(conn, table)
            if not available_columns:
                return jsonify({"error": f"Table '{table}' not found or has no columns"}), 404

            # Quote table name
            if '.' in table:
                schema, tbl = table.split('.', 1)
                quoted_table = f"{quote_ident_with_conn(schema, conn)}.{quote_ident_with_conn(tbl, conn)}"
            else:
                quoted_table = quote_ident_with_conn(table, conn)

            query = f"SELECT COUNT(*) FROM {quoted_table}"
            params = []

            where_clause, where_params = build_where_clause(filters, available_columns, conn)
            if where_clause:
                query += f" {where_clause}"
                params.extend(where_params)

            with conn.cursor() as cur:
                cur.execute(query, params)
                count = cur.fetchone()[0]

            return jsonify({
                "table": table,
                "count": count
            })
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/query/distinct', methods=['POST'])
def distinct_values():
    """Get distinct values for a column, optionally filtered."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body is required"}), 400

        table = data.get('table')
        column = data.get('column')
        if not table or not column:
            return jsonify({"error": "Table name and column are required"}), 400

        is_valid, error_msg = validate_table_name(table)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

        filters = data.get('filters', [])
        limit = min(data.get('limit', 1000), MAX_LIMIT)

        conn = get_db_connection()
        try:
            available_columns = get_table_columns(conn, table)
            if not available_columns:
                return jsonify({"error": f"Table '{table}' not found"}), 404

            if column not in available_columns:
                return jsonify({"error": f"Column '{column}' not found in table '{table}'"}), 400

            if '.' in table:
                schema, tbl = table.split('.', 1)
                quoted_table = f"{quote_ident_with_conn(schema, conn)}.{quote_ident_with_conn(tbl, conn)}"
            else:
                quoted_table = quote_ident_with_conn(table, conn)

            quoted_column = quote_ident_with_conn(column, conn)
            query = f"SELECT DISTINCT {quoted_column} FROM {quoted_table}"
            params = []

            where_clause, where_params = build_where_clause(filters, available_columns, conn)
            if where_clause:
                query += f" {where_clause}"
                params.extend(where_params)

            query += f" ORDER BY {quoted_column} LIMIT %s"
            params.append(limit)

            with conn.cursor() as cur:
                cur.execute(query, params)
                values = [row[0] for row in cur.fetchall()]

            return jsonify({
                "table": table,
                "column": column,
                "distinct_count": len(values),
                "values": values
            })
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/query/aggregate', methods=['POST'])
def aggregate_query():
    """
    Run aggregation queries.
    
    Request body:
    {
        "table": "orders",
        "aggregations": [
            {"function": "SUM", "column": "amount", "alias": "total_amount"},
            {"function": "COUNT", "column": "*", "alias": "order_count"},
            {"function": "AVG", "column": "amount", "alias": "avg_amount"}
        ],
        "group_by": ["status", "region"],
        "filters": [...],
        "having": [...],
        "order_by": [...],
        "limit": 100
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body is required"}), 400

        table = data.get('table')
        if not table:
            return jsonify({"error": "Table name is required"}), 400

        is_valid, error_msg = validate_table_name(table)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

        aggregations = data.get('aggregations', [])
        if not aggregations:
            return jsonify({"error": "At least one aggregation is required"}), 400

        group_by = data.get('group_by', [])
        filters = data.get('filters', [])
        having = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = min(data.get('limit', DEFAULT_LIMIT), MAX_LIMIT)
        offset = data.get('offset', 0)

        conn = get_db_connection()
        try:
            available_columns = get_table_columns(conn, table)
            if not available_columns:
                return jsonify({"error": f"Table '{table}' not found"}), 404

            # Build SELECT clause with aggregations and group by columns
            select_parts = []

            # Add group by columns first
            for col in group_by:
                if col not in available_columns:
                    return jsonify({"error": f"Invalid GROUP BY column: {col}"}), 400
                select_parts.append(quote_ident_with_conn(col, conn))

            # Add aggregations
            for agg in aggregations:
                func = agg.get('function', '').upper()
                col = agg.get('column', '*')
                alias = agg.get('alias', f"{func.lower()}_{col}")

                if func not in ALLOWED_AGGREGATIONS:
                    return jsonify({"error": f"Invalid aggregation function: {func}"}), 400

                if col == '*':
                    agg_expr = f"{func}(*)"
                elif col in available_columns:
                    agg_expr = f"{func}({quote_ident_with_conn(col, conn)})"
                else:
                    return jsonify({"error": f"Invalid column in aggregation: {col}"}), 400

                if validate_identifier(alias):
                    agg_expr += f" AS {quote_ident_with_conn(alias, conn)}"

                select_parts.append(agg_expr)

            # Build query
            if '.' in table:
                schema, tbl = table.split('.', 1)
                quoted_table = f"{quote_ident_with_conn(schema, conn)}.{quote_ident_with_conn(tbl, conn)}"
            else:
                quoted_table = quote_ident_with_conn(table, conn)

            query = f"SELECT {', '.join(select_parts)} FROM {quoted_table}"
            params = []

            # WHERE
            where_clause, where_params = build_where_clause(filters, available_columns, conn)
            if where_clause:
                query += f" {where_clause}"
                params.extend(where_params)

            # GROUP BY
            group_clause = build_group_by_clause(group_by, available_columns, conn)
            if group_clause:
                query += f" {group_clause}"

            # HAVING
            having_clause, having_params = build_having_clause(having, conn)
            if having_clause:
                query += f" {having_clause}"
                params.extend(having_params)

            # ORDER BY
            order_clause = build_order_by_clause(order_by, available_columns, conn)
            if order_clause:
                query += f" {order_clause}"

            # LIMIT & OFFSET
            query += " LIMIT %s"
            params.append(limit)
            if offset:
                query += " OFFSET %s"
                params.append(int(offset))

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, params)
                rows = cur.fetchall()
                col_names = [desc[0] for desc in cur.description] if cur.description else []

            results = [dict(row) for row in rows]

            return jsonify({
                "table": table,
                "columns": col_names,
                "row_count": len(results),
                "data": results
            })
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": f"Database error: {str(e)}"}), 500


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint that also verifies database connectivity."""
    try:
        conn = get_db_connection()
        with conn.cursor() as cur:
            cur.execute("SELECT 1")
        conn.close()
        return jsonify({"status": "healthy", "database": "connected"})
    except psycopg2.Error as e:
        return jsonify({"status": "unhealthy", "database": str(e)}), 503


@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Endpoint not found"}), 404


@app.errorhandler(405)
def method_not_allowed(e):
    return jsonify({"error": "Method not allowed"}), 405


@app.errorhandler(500)
def internal_error(e):
    return jsonify({"error": "Internal server error"}), 500


if __name__ == '__main__':
    port = int(os.environ.get('PORT', 5000))
    debug = os.environ.get('FLASK_DEBUG', 'false').lower() == 'true'
    app.run(host='0.0.0.0', port=port, debug=debug)